import { useState, useEffect } from "react";
import MovieList from "./components/MovieList/MovieList";
import MoviePopup from "./components/MoviePopup/MoviePopup";
import MovieItem from "./components/MovieItem/MovieItem";
import AddMovie from "./components/AddMovie/AddMovie";
import Favorites from "./components/Favorite/Favorite";
import { useWindowWidth } from "./hooks/useWindowWidth";
import { searchMovies } from "./services/Api";
import "./App.css";
import "./index.css"

function App() {
  const width = useWindowWidth();
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedMovie, setSelectedMovie] = useState(null);
  const [hasSearched, setHasSearched] = useState(false);
  // This loads your saved movies from the browser's memory when the app starts
  const [favorites, setFavorites] = useState(() => {
    const savedData = localStorage.getItem("my-watchlist");
    return savedData ? JSON.parse(savedData) : [];
  });

  useEffect(() => {
    performSearch("dune");
  }, []);

  const performSearch = async (term = searchTerm) => {
    const finalTerm = term.trim() || "dune";

    setLoading(true);
    setHasSearched(finalTerm !== "dune");

    const results = await searchMovies(finalTerm);
    setMovies(results);
    setLoading(false);
  };

  const handleDeleteMovie = (id) => {
    setMovies(movies.filter((movie) => movie.id !== id));
    setSelectedMovie(null);
  };

  const handleUpdateMovie = (id, newTitle) => {
    setMovies(movies.map((m) => (m.id === id ? { ...m, title: newTitle } : m)));
  };

  const handleAddToFavorites = async (movie) => {
    let movieToAdd;

    // Check if we received an object from AddMovie or a string/object from search
    if (typeof movie === "string") {
      const results = await searchMovies(movie);
      movieToAdd = results.length > 0 ? results[0] : { id: Date.now(), title: movie, poster: "N/A" };
    } else if (movie.id && movie.id.toString().startsWith('custom-')) {
      // If it's from your AddMovie component, it already has the custom ID/Title
      // Let's try to fetch a real poster for it using the title!
      const results = await searchMovies(movie.title);
      if (results && results.length > 0) {
        movieToAdd = results[0];
      } else {
        movieToAdd = movie; // Keep custom object if search fails
      }
    } else {
      movieToAdd = movie;
    }

    if (!favorites.some((fav) => fav.id === movieToAdd.id)) {
      setFavorites([...favorites, movieToAdd]);
    }
  };

  return (
    <div className="app-container">
      {/* FIXED NAVBAR: Distinction for UI focus */}
      <nav className="navbar">
        <div className="logo">VELLUM</div>
        <div className="nav-actions">
          <div className="search-wrapper">
            <input
              type="text"
              placeholder="Search titles..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && performSearch()}
            />
            <button onClick={() => performSearch()}>🔍</button>
          </div>
        </div>
      </nav>

      {/* HERO SECTION: Now purely cinematic */}
      <div className="hero">
        <div className="hero-overlay"></div> {/* Add this for the fade effect */}
        <div className="hero-content">
          <h1>Unlimited movies, series and more</h1>
          <p>Your portal to world-class entertainment.</p>
          <div className="hero-btns">
            <button className="btn-play">▶ Play</button>
            <button className="btn-info">ⓘ More Info</button>
          </div>
        </div>
      </div>

      <div className="content-area">
        {/* ADD MOVIE: Distinction for UX - keep it separate or in a modal */}
        <section className="admin-section">
          <AddMovie onAdd={handleAddToFavorites} />
        </section>

        {favorites.length > 0 && (
          <section className="row">
            <Favorites favorites={favorites} onSelect={setSelectedMovie} />
          </section>
        )}

        <section className="row">
          <h2>{hasSearched ? `Results for: ${searchTerm}` : "Trending Movies"}</h2>
          {loading ? (
            <div className="loader">Loading...</div>
          ) : (
            <MovieList movies={movies} onSelect={setSelectedMovie} />
          )}
        </section>
      </div>

      {selectedMovie && (
        <MoviePopup
          movie={selectedMovie}
          onClose={() => setSelectedMovie(null)}
          onDelete={handleDeleteMovie}
          onUpdate={handleUpdateMovie}
        />
      )}
    </div>
  );
}

export default App;
